#include <iostream>
#include <algorithm>
using namespace std;
int a[999];
int main()
{
    string s;
    int quan=1,ans=0,n,m;
    cin>>n>>s>>m;
    for(int i=s.size()-1;i>=0;i--)
    {
        if(s[i]>='0'&&s[i]<='9')
        {
            ans=ans+(s[i]-'0')*quan;
        }
        else
        {
            ans=ans+(s[i]-'A'+10)*quan;
        }
        quan*=n;
    }
    int count=0;
    while(ans!=0)
    {
        a[++count]=ans%m;
        ans/=m;
    }
    for(int i=count;i>=1;i--)
    {
        if(a[i]>=10)
        {
            cout<<(char)(a[i]+'A'-10);
        }
        else
        {
            cout<<a[i];
        }
    }
    return 0;
}
